using System;
using Atlas.DataTypes;
using Atlas.Serialization;

namespace Atlas.Client;

/// <summary>
/// Base class for client-side entities. Game scripts derive from this
/// and implement partial methods generated by Atlas.Generators.Def.
/// </summary>
public abstract class ClientEntity
{
    public uint EntityId { get; internal set; }
    public bool IsDestroyed { get; internal set; }

    public abstract string TypeName { get; }

    /// <summary>Restores entity state received from the server (implemented by source generator).</summary>
    public virtual void Deserialize(ref SpanReader reader) { }

    /// <summary>
    /// Apply an owner-scope snapshot (fields visible to the entity's owning
    /// client: <c>OwnClient</c>, <c>AllClients</c>, <c>CellPublicAndOwn</c>,
    /// <c>BaseAndClient</c>). Paired with the server's
    /// <c>SerializeForOwnerClient</c>. Used by the baseline channel
    /// (<c>0xF002</c>) for the local player's own entity. Writes directly
    /// to backing fields — does NOT fire <c>OnXxxChanged</c>, matching
    /// BigWorld's initial-snapshot semantics.
    /// </summary>
    public virtual void ApplyOwnerSnapshot(ref SpanReader reader) { }

    /// <summary>
    /// Apply an other-scope snapshot (fields visible to non-owner
    /// observers: <c>AllClients</c>, <c>OtherClients</c>). Paired with the
    /// server's <c>SerializeForOtherClients</c>. Used by the AoI enter
    /// envelope (<c>kEntityEnter</c>) when a peer joins the local player's
    /// view. Same direct-write semantics as <see cref="ApplyOwnerSnapshot"/>.
    /// </summary>
    public virtual void ApplyOtherSnapshot(ref SpanReader reader) { }

    /// <summary>
    /// Apply an incremental property delta as produced by the server's
    /// <c>SerializeReplicatedDelta*</c> family. The wire body is a dirty-flag
    /// bitmap followed by the changed field values. The generator overrides
    /// this in Phase B of the client-sync rework (<c>PROPERTY_SYNC_DESIGN.md</c>
    /// §9.5 task 9.1); the base no-op keeps the dispatcher valid before the
    /// generator change lands.
    /// </summary>
    public virtual void ApplyReplicatedDelta(ref SpanReader reader) { }

    /// <summary>
    /// Apply a volatile position/orientation update from the AoI volatile
    /// channel (<c>kEntityPositionUpdate</c> envelope). Phase B4 wires this
    /// to a generator-produced position field and an <c>OnPositionUpdated</c>
    /// script hook; in Phase A the base simply drops the update.
    /// </summary>
    public virtual void ApplyPositionUpdate(Vector3 pos, Vector3 dir, bool onGround) { }

    /// <summary>Called when the entity is created on the client.</summary>
    protected internal virtual void OnInit() { }

    /// <summary>
    /// Called once after the entity has been fully initialised into the
    /// local player's world — factory creation, initial transform, and
    /// the other-scope snapshot from the AoI <c>kEntityEnter</c> envelope
    /// have all been applied. Scripts override this for setup that needs
    /// the complete starting state (attach visuals, register timers, etc.).
    /// BigWorld analogue: <c>BWEntity::onEnterWorld</c>. Distinct from
    /// <see cref="OnInit"/> which fires on the bare instance before any
    /// server state is consumed.
    /// </summary>
    protected internal virtual void OnEnterWorld() { }

    /// <summary>Called when the entity is destroyed on the client.</summary>
    protected internal virtual void OnDestroy() { }

    // =========================================================================
    // RPC send infrastructure — for sending exposed RPCs to the server.
    // Client has no SendClientRpc (can't send client methods to itself).
    // =========================================================================

    protected internal void SendCellRpc(int rpcId, ReadOnlySpan<byte> payload)
    {
        ClientNativeApi.SendCellRpc(EntityId, (uint)rpcId, payload);
    }

    protected internal void SendBaseRpc(int rpcId, ReadOnlySpan<byte> payload)
    {
        ClientNativeApi.SendBaseRpc(EntityId, (uint)rpcId, payload);
    }
}
